  void tech_map_impl<Ntk, CutSize, CutData, NInputs, Configuration>::match_phase(node<Ntk> const &n, uint8_t phase) {
    // Adaptive simulated annealing with exponential cooling and periodic boosts
    static double temperature = 50.0; // Higher initial temperature for broader exploration
    static const double base_cooling_rate = 0.97;
    static double cooling_rate = base_cooling_rate;
    static const double min_temperature = 0.001;
    static const double temperature_boost = 10.0; // Periodic boosts to escape local minima
    static int iteration = 0;
    static int accept_count = 0; // Track acceptance rate

    double best_arrival = std::numeric_limits<double>::max();
    double best_area_flow = std::numeric_limits<double>::max();
    float best_area = std::numeric_limits<float>::max();
    uint32_t best_size = UINT32_MAX;
    uint8_t best_cut = 0u;
    uint8_t best_phase = 0u;
    uint8_t cut_index = 0u;

    // Initialize current solution
    double current_arrival = best_arrival;
    double current_area_flow = best_area_flow;
    auto index = ntk.node_to_index(n);

    auto &node_data = node_match[index];
    auto &cut_matches = matches[index];
    supergate<NInputs> const *best_supergate = node_data.best_supergate[phase];

    /* recompute best match info */
    if (best_supergate != nullptr) {
      auto const &cut = cuts.cuts(index)[node_data.best_cut[phase]];

      best_phase = node_data.phase[phase];
      best_arrival = 0.0f;
      best_area_flow = best_supergate->area + cut_leaves_flow(cut, n, phase);
      best_area = best_supergate->area;
      best_cut = node_data.best_cut[phase];
      best_size = cut.size();

      auto ctr = 0u;
      for (auto l : cut) {
        double arrival_pin = node_match[l].arrival[(best_phase >> ctr) & 1] + best_supergate->tdelay[ctr];
        best_arrival = std::max(best_arrival, arrival_pin);
        ++ctr;
      }
    }

    /* foreach cut */
    for (auto &cut : cuts.cuts(index)) {
      /* trivial cuts or not matched cuts */
      if ((*cut)->data.ignore) {
        ++cut_index;
        continue;
      }

      auto const &supergates = cut_matches[(*cut)->data.match_index].supergates;
      auto const negation = cut_matches[(*cut)->data.match_index].negations[phase];

      if (supergates[phase] == nullptr) {
        ++cut_index;
        continue;
      }

      /* match each gate and take the best one */
      for (auto const &gate : *supergates[phase]) {
        uint8_t gate_polarity = gate.polarity ^ negation;
        node_data.phase[phase] = gate_polarity;
        double area_local = gate.area + cut_leaves_flow(*cut, n, phase);
        double worst_arrival = 0.0f;

        auto ctr = 0u;
        for (auto l : *cut) {
          double arrival_pin = node_match[l].arrival[(gate_polarity >> ctr) & 1] + gate.tdelay[ctr];
          worst_arrival = std::max(worst_arrival, arrival_pin);
          ++ctr;
        }

        if constexpr (DO_AREA) {
          if (worst_arrival > node_data.required[phase] + epsilon)
            continue;
        }

        bool accept = false;
        if (compare_map<DO_AREA>(worst_arrival, best_arrival, area_local, best_area_flow, cut->size(), best_size)) {
            accept = true;
        } else {
            // Adaptive weighted probability with temperature-dependent weights
            double progress = temperature / 50.0; // Normalized temperature
            double arrival_weight = 0.7 + 0.3 * progress; // Higher weight for arrival early on
            double area_weight = 1.0 - arrival_weight;
            double normalized_delta = (worst_arrival - best_arrival)/best_arrival + 
                                    (area_local - best_area_flow)/best_area_flow;
            double probability = exp(-normalized_delta / (temperature * (1.0 + iteration/10000.0)));
            accept = (rand() / (double)RAND_MAX) < probability;
            iteration++;
            if (accept) accept_count++;
        }

        if (accept) {
            best_arrival = worst_arrival;
            best_area_flow = area_local;
            best_size = cut->size();
            best_cut = cut_index;
            best_area = gate.area;
            best_phase = gate_polarity;
            best_supergate = &gate;
        }
      }

      ++cut_index;
    }

    node_data.flows[phase] = best_area_flow;
    node_data.arrival[phase] = best_arrival;
    node_data.area[phase] = best_area;
    node_data.best_cut[phase] = best_cut;
    node_data.phase[phase] = best_phase;
    node_data.best_supergate[phase] = best_supergate;

    // Update temperature with bounds checking
    if (temperature > min_temperature) {
        temperature *= cooling_rate;
    }

    // Enhanced adaptive restart with diversity maintenance
    static int restart_counter = 0;
    static double last_best_arrival = best_arrival;
    restart_counter++;

    // Restart conditions: stagnation or low temperature
    bool stagnation = (restart_counter > 500 && 
                      fabs(best_arrival - last_best_arrival)/last_best_arrival < 0.01);
    bool low_temp = (restart_counter > 1000 && temperature < 0.1);

    if (stagnation || low_temp) {
        temperature = temperature_boost * (0.8 + 0.4 * (double)rand()/RAND_MAX);
        cooling_rate = base_cooling_rate * (0.95 + 0.1 * (double)rand()/RAND_MAX);
        restart_counter = 0;
        accept_count = 0;
        last_best_arrival = best_arrival;
        // Perturb current best to maintain diversity
        best_arrival *= (1.0 + 0.05 * (double)rand()/RAND_MAX);
        best_area_flow *= (1.0 + 0.05 * (double)rand()/RAND_MAX);
    }
